import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

async function verifyContent(content: string, topic: string) {
  const result = await vex.verify({
    content,
    context: { topic },
    checks: [
      {
        name: 'brand_consistency',
        type: 'semantic_similarity',
        reference: 'brand_voice_profile',
        threshold: 0.88
      },
      {
        name: 'seo_compliance',
        type: 'seo_analysis',
        keywords: ['AI', 'content', 'generation'],
        readability: { min: 60 }
      },
      {
        name: 'tone_adherence',
        type: 'sentiment_tone',
        requiredTone: 'professional',
        confidence: 0.9
      }
    ]
  });

  return result;
}
